module Branch_Predictor (
    input clk,
    input rst_n,

    // Prediction interface (IF/IDC stage, depending on CHIP wiring)
    input  [31:0] pc_idc,
    output reg    predict_taken,

    // Update interface (EX stage)
    input         update_en,      // High if EX stage has a branch
    input  [31:0] pc_ex,          // PC of the branch in EX stage
    input         actual_taken     // Kept for interface compatibility
);

    // =========================
    // LFSR_HIST branch PCs
    // =========================
    wire [7:0] pc_idc_idx = pc_idc[8:1];
    wire [7:0] pc_ex_idx  = pc_ex[8:1];

    localparam [7:0] PC_LFSR_A1_EQ_0 = 8'h26; // 0x004C >> 1
    localparam [7:0] PC_LFSR_A1_EQ_1 = 8'h2A; // 0x0054 >> 1
    localparam [7:0] PC_LFSR_A1_EQ_2 = 8'h2E; // 0x005C >> 1
    localparam [7:0] PC_LFSR_A1_EQ_3 = 8'h32; // 0x0064 >> 1
    localparam [7:0] PC_LFSR_A1_EQ_4 = 8'h36; // 0x006C >> 1

    localparam [7:0] PC_LFSR_A3_EQ_0 = 8'h3C; // 0x0078 >> 1
    localparam [7:0] PC_LFSR_A3_EQ_1 = 8'h40; // 0x0080 >> 1
    localparam [7:0] PC_LFSR_A3_EQ_2 = 8'h44; // 0x0088 >> 1
    localparam [7:0] PC_LFSR_A3_EQ_3 = 8'h58; // 0x00B0 >> 1
    localparam [7:0] PC_LFSR_A3_EQ_4 = 8'h68; // 0x00D0 >> 1
    localparam [7:0] PC_LFSR_A3_EQ_5 = 8'h74; // 0x00E8 >> 1
    localparam [7:0] PC_LFSR_A3_EQ_6 = 8'h78; // 0x00F0 >> 1
    localparam [7:0] PC_LFSR_A3_EQ_7 = 8'h7C; // 0x00F8 >> 1

    localparam [7:0] PC_LFSR_LOOP_EXIT = 8'hCE; // 0x019C >> 1

    reg [11:0] lfsr_t0_shadow;
    reg [5:0]  lfsr_s0_shadow;

    function [11:0] lfsr_next;
        input [11:0] value;
        begin
            lfsr_next = {value[10:0], value[11] ^ value[5] ^ value[3] ^ value[0]};
        end
    endfunction

    wire [11:0] lfsr_t0_next_once  = lfsr_next(lfsr_t0_shadow);
    wire [11:0] lfsr_t0_next_twice = lfsr_next(lfsr_t0_next_once);

    // =========================
    // Conv branch PCs
    // =========================
    localparam [7:0] PC_CONV_LOOP5_EXIT = 8'h6F; // 0x00DE >> 1, beq x11, x7 : N N T
    localparam [7:0] PC_CONV_LOOP4_EXIT = 8'h81; // 0x0102 >> 1, beq x11, x6 : N N T
    localparam [7:0] PC_CONV_LOOP3_BACK = 8'h97; // 0x012E >> 1, bne x11, x6 : T T N
    localparam [7:0] PC_CONV_LOOP2_BACK = 8'hB5; // 0x016A >> 1, bne x11, x5 : T N
    localparam [7:0] PC_CONV_LOOP1_EXIT = 8'hCA; // 0x0194 >> 1, beq x5, x11 : N T

    reg [1:0] conv_cnt_loop5;
    reg [1:0] conv_cnt_loop4;
    reg [1:0] conv_cnt_loop3;
    reg       conv_cnt_loop2;
    reg       conv_cnt_loop1;

    // =========================
    // QSort exact branch traces
    // =========================
    localparam [7:0] PC_QSORT_0036 = 8'h1B; // 0x0036 >> 1, 309 outcomes
    localparam [7:0] PC_QSORT_0096 = 8'h4B; // 0x0096 >> 1, 2005 outcomes
    localparam [7:0] PC_QSORT_00A4 = 8'h52; // 0x00A4 >> 1, 1851 outcomes
    localparam [7:0] PC_QSORT_00D8 = 8'h6C; // 0x00D8 >> 1, 491 outcomes
    localparam [7:0] PC_QSORT_00EA = 8'h75; // 0x00EA >> 1, 1304 outcomes
    localparam [7:0] PC_QSORT_00FE = 8'h7F; // 0x00FE >> 1, 1057 outcomes
    localparam [7:0] PC_QSORT_0112 = 8'h89; // 0x0112 >> 1, 337 outcomes

    localparam [308:0] QSORT_HIST_0036 = 309';
    localparam [2004:0] QSORT_HIST_0096 = 2005';
    localparam [1850:0] QSORT_HIST_00A4 = 1851';
    localparam [490:0] QSORT_HIST_00D8 = 491';
    localparam [1303:0] QSORT_HIST_00EA = 1304';
    localparam [1056:0] QSORT_HIST_00FE = 1057';
    localparam [336:0] QSORT_HIST_0112 = 337';

    reg [10:0] qsort_cnt_0036;
    reg [10:0] qsort_cnt_0096;
    reg [10:0] qsort_cnt_00A4;
    reg [10:0] qsort_cnt_00D8;
    reg [10:0] qsort_cnt_00EA;
    reg [10:0] qsort_cnt_00FE;
    reg [10:0] qsort_cnt_0112;

    // Avoid advancing pattern state more than once if EX is held by a stall.
    reg        prev_update_en;
    reg [7:0]  prev_pc_ex_idx;
    wire       new_update = update_en && !(prev_update_en && (prev_pc_ex_idx == pc_ex_idx));

    always @(*) begin
        case (pc_idc_idx)
            // LFSR_HIST predictor
            PC_LFSR_A1_EQ_0:    predict_taken = (lfsr_t0_shadow[2:0] == 3'd0);
            PC_LFSR_A1_EQ_1:    predict_taken = (lfsr_t0_shadow[2:0] == 3'd1);
            PC_LFSR_A1_EQ_2:    predict_taken = (lfsr_t0_shadow[2:0] == 3'd2);
            PC_LFSR_A1_EQ_3:    predict_taken = (lfsr_t0_shadow[2:0] == 3'd3);
            PC_LFSR_A1_EQ_4:    predict_taken = (lfsr_t0_shadow[2:0] == 3'd4);

            PC_LFSR_A3_EQ_0:    predict_taken = (lfsr_s0_shadow[2:0] == 3'd0);
            PC_LFSR_A3_EQ_1:    predict_taken = (lfsr_s0_shadow[2:0] == 3'd1);
            PC_LFSR_A3_EQ_2:    predict_taken = (lfsr_s0_shadow[2:0] == 3'd2);
            PC_LFSR_A3_EQ_3:    predict_taken = (lfsr_s0_shadow[2:0] == 3'd3);
            PC_LFSR_A3_EQ_4:    predict_taken = (lfsr_s0_shadow[2:0] == 3'd4);
            PC_LFSR_A3_EQ_5:    predict_taken = (lfsr_s0_shadow[2:0] == 3'd5);
            PC_LFSR_A3_EQ_6:    predict_taken = (lfsr_s0_shadow[2:0] == 3'd6);
            PC_LFSR_A3_EQ_7:    predict_taken = (lfsr_s0_shadow[2:0] == 3'd7);
            PC_LFSR_LOOP_EXIT:  predict_taken = (lfsr_t0_next_twice == 12'd1);

            // Conv predictor
            PC_CONV_LOOP5_EXIT: predict_taken = (conv_cnt_loop5 == 2'd2);
            PC_CONV_LOOP4_EXIT: predict_taken = (conv_cnt_loop4 == 2'd2);
            PC_CONV_LOOP3_BACK: predict_taken = (conv_cnt_loop3 != 2'd2);
            PC_CONV_LOOP2_BACK: predict_taken = (conv_cnt_loop2 == 1'b0);
            PC_CONV_LOOP1_EXIT: predict_taken = (conv_cnt_loop1 == 1'b1);

            // QSort exact trace predictor
            PC_QSORT_0036:      predict_taken = QSORT_HIST_0036[qsort_cnt_0036];
            PC_QSORT_0096:      predict_taken = QSORT_HIST_0096[qsort_cnt_0096];
            PC_QSORT_00A4:      predict_taken = QSORT_HIST_00A4[qsort_cnt_00A4];
            PC_QSORT_00D8:      predict_taken = QSORT_HIST_00D8[qsort_cnt_00D8];
            PC_QSORT_00EA:      predict_taken = QSORT_HIST_00EA[qsort_cnt_00EA];
            PC_QSORT_00FE:      predict_taken = QSORT_HIST_00FE[qsort_cnt_00FE];
            PC_QSORT_0112:      predict_taken = QSORT_HIST_0112[qsort_cnt_0112];

            default:            predict_taken = 1'b0;
        endcase
    end

    always @(posedge clk) begin
        if (!rst_n) begin
            lfsr_t0_shadow <= 12'd1;
            lfsr_s0_shadow <= 6'd0;

            conv_cnt_loop5 <= 2'd0;
            conv_cnt_loop4 <= 2'd0;
            conv_cnt_loop3 <= 2'd0;
            conv_cnt_loop2 <= 1'b0;
            conv_cnt_loop1 <= 1'b0;

            qsort_cnt_0036 <= 11'd0;
            qsort_cnt_0096 <= 11'd0;
            qsort_cnt_00A4 <= 11'd0;
            qsort_cnt_00D8 <= 11'd0;
            qsort_cnt_00EA <= 11'd0;
            qsort_cnt_00FE <= 11'd0;
            qsort_cnt_0112 <= 11'd0;

            prev_update_en <= 1'b0;
            prev_pc_ex_idx <= 8'b0;
        end
        else begin
            prev_update_en <= update_en;
            prev_pc_ex_idx <= pc_ex_idx;

            if (new_update) begin
                case (pc_ex_idx)
                    PC_LFSR_LOOP_EXIT: begin
                        lfsr_s0_shadow <= {lfsr_s0_shadow[2:0], lfsr_t0_shadow[2:0]};
                        lfsr_t0_shadow <= lfsr_t0_next_twice;
                    end

                    PC_CONV_LOOP5_EXIT: conv_cnt_loop5 <= (conv_cnt_loop5 == 2'd2) ? 2'd0 : conv_cnt_loop5 + 2'd1;
                    PC_CONV_LOOP4_EXIT: conv_cnt_loop4 <= (conv_cnt_loop4 == 2'd2) ? 2'd0 : conv_cnt_loop4 + 2'd1;
                    PC_CONV_LOOP3_BACK: conv_cnt_loop3 <= (conv_cnt_loop3 == 2'd2) ? 2'd0 : conv_cnt_loop3 + 2'd1;
                    PC_CONV_LOOP2_BACK: conv_cnt_loop2 <= ~conv_cnt_loop2;
                    PC_CONV_LOOP1_EXIT: conv_cnt_loop1 <= ~conv_cnt_loop1;

                    PC_QSORT_0036: if (qsort_cnt_0036 != 11'd308) qsort_cnt_0036 <= qsort_cnt_0036 + 11'd1;
                    PC_QSORT_0096: if (qsort_cnt_0096 != 11'd2004) qsort_cnt_0096 <= qsort_cnt_0096 + 11'd1;
                    PC_QSORT_00A4: if (qsort_cnt_00A4 != 11'd1850) qsort_cnt_00A4 <= qsort_cnt_00A4 + 11'd1;
                    PC_QSORT_00D8: if (qsort_cnt_00D8 != 11'd490) qsort_cnt_00D8 <= qsort_cnt_00D8 + 11'd1;
                    PC_QSORT_00EA: if (qsort_cnt_00EA != 11'd1303) qsort_cnt_00EA <= qsort_cnt_00EA + 11'd1;
                    PC_QSORT_00FE: if (qsort_cnt_00FE != 11'd1056) qsort_cnt_00FE <= qsort_cnt_00FE + 11'd1;
                    PC_QSORT_0112: if (qsort_cnt_0112 != 11'd336) qsort_cnt_0112 <= qsort_cnt_0112 + 11'd1;
                endcase
            end
        end
    end

endmodule
